mapper.select:
SELECT t.ticket_id, t.ticket_no, t.title, t.priority, t.status,
       c.category_name,
       u.nick_name AS creator_name,
       a.nick_name AS assignee_name,
       t.create_time, t.update_time, t.response_due_at, t.resolve_due_at,
       t.response_overdue, t.resolve_overdue
FROM ticket t
LEFT JOIN ticket_category c ON c.category_id = t.category_id
LEFT JOIN sys_user u ON u.user_id = t.creator_id
LEFT JOIN sys_user a ON a.user_id = t.assignee_id
WHERE t.del_flag = '0'

    AND t.status = #{status}


    AND t.priority = #{priority}


    AND t.category_id = #{categoryId}


    AND (t.title LIKE CONCAT('%', #{keyword}, '%') OR t.content LIKE CONCAT('%', #{keyword}, '%'))


    AND t.create_time >= #{beginTime}


    AND t.create_time <= #{endTime}


    AND t.response_overdue = #{responseOverdue}


    AND t.resolve_overdue = #{resolveOverdue}



    AND 1 = 0


    AND (
        t.creator_id = #{accessScope.userId}
        OR t.assignee_id = #{accessScope.userId}

            OR t.dept_id = #{accessScope.deptId}


            OR t.dept_id IN (
                SELECT d.dept_id
                FROM sys_dept d
                WHERE d.dept_id = #{accessScope.deptId}
                   OR FIND_IN_SET(#{accessScope.deptId}, d.ancestors)
            )


            OR t.dept_id IN (
                SELECT rd.dept_id
                FROM sys_role_dept rd
                WHERE rd.role_id IN

                    #{roleId}

            )

    )

ORDER BY t.create_time DESC

SELECT t.ticket_id
FROM ticket t
WHERE t.ticket_id IN

    #{ticketId}

  AND t.del_flag = '0'

  AND (
      t.creator_id = #{scope.userId} OR t.assignee_id = #{scope.userId}
       OR t.dept_id = #{scope.deptId} 

          OR t.dept_id IN (SELECT d.dept_id FROM sys_dept d
              WHERE d.dept_id = #{scope.deptId} OR FIND_IN_SET(#{scope.deptId}, d.ancestors))


          OR t.dept_id IN (SELECT rd.dept_id FROM sys_role_dept rd WHERE rd.role_id IN

                  #{roleId}
              )

  )

ORDER BY FIELD(t.ticket_id,
#{ticketId})

SELECT ticket_id FROM ticket
WHERE del_flag = '0' AND ticket_id > #{lastTicketId} AND ticket_id <= #{maxTicketId}
ORDER BY ticket_id
LIMIT #{limit}

SELECT COUNT(*)
FROM ticket t
WHERE t.ticket_id = #{ticketId}
  AND t.del_flag = '0'

  AND (
      t.creator_id = #{scope.userId}
      OR t.assignee_id = #{scope.userId}

          OR t.dept_id = #{scope.deptId}


          OR t.dept_id IN (
              SELECT d.dept_id
              FROM sys_dept d
              WHERE d.dept_id = #{scope.deptId}
                 OR FIND_IN_SET(#{scope.deptId}, d.ancestors)
          )


          OR t.dept_id IN (
              SELECT rd.dept_id
              FROM sys_role_dept rd
              WHERE rd.role_id IN

                  #{roleId}

          )

  )
